#include<bits/stdc++.h>
using namespace std;
long long mod,a[5000010],s[5000010],t[5000010];
long long read()
{
    long long x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar();
    }
    return x;
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
int main()
{
    long long n,k;
    scanf("%lld%lld%lld",&n,&mod,&k);
    s[0]=t[0]=1;
    for(long long i=1;i<=n;i++)
    {
        a[i]=read();
        s[i]=s[i-1]*a[i]%mod;
    }
    t[n]=fastpow(s[n],mod-2);
    for(long long i=n-1;i>=1;i--)
    {
        t[i]=t[i+1]*a[i+1]%mod;
    }
    long long sum=1,ans=0;
    for(long long i=1;i<=n;i++)
    {
        sum=sum*k%mod;
        long long inv=t[i]*s[i-1]%mod;
        ans+=inv*sum%mod;
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
